+        // Complete mode: Q is 3x3, R is 3x3
+        assert_eq!(result.q.len(), 9);
+        assert_eq!(result.r.len(), 9);
+
+        // Q should be orthogonal (Q^T @ Q == I)
+        let qtq = mat_mul_nn(&transpose_mat(&result.q, 3, 3), &result.q, 3);
