+            format!("{prefix}.{name}")
+        };
+        result.push((full, id));
+    }
+    for (child_name, child) in module.named_children() {
+        let child_prefix = if prefix.is_empty() {
+            child_name
+        } else {
+            format!("{prefix}.{child_name}")
+        };
+        result.extend(named_parameters(child, &child_prefix));
+    }
+    result
